// Extract first CSV or Excel attachment from email
const items = $input.all();
const results = [];

for (const item of items) {
  const attachments = item.json.attachments || [];

  // Find the first CSV or Excel file
  const supported = attachments.filter(a => {
    const name = (a.filename || a.name || '').toLowerCase();
    return name.endsWith('.csv') || name.endsWith('.xlsx') || name.endsWith('.xls');
  });

  if (supported.length === 0) {
    throw new Error('No supported attachment found (expected .csv, .xlsx, or .xls). Subject: ' + (item.json.subject || 'unknown'));
  }

  const attachment = supported[0];
  const filename = attachment.filename || attachment.name || 'attachment';
  const fileType = filename.toLowerCase().endsWith('.csv') ? 'csv' : 'xlsx';

  results.push({
    json: {
      filename,
      fileType,
      emailSubject: item.json.subject || '',
      emailFrom: item.json.from || '',
      receivedAt: item.json.date || new Date().toISOString(),
      attachmentContent: attachment.content,
      mimeType: attachment.type || (fileType === 'csv' ? 'text/csv' : 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet')
    },
    binary: {
      data: {
        data: attachment.content,
        mimeType: attachment.type || 'text/csv',
        fileName: filename
      }
    }
  });
}

return results;

// Validate and transform each row
const items = $input.all();
const valid = [];
const invalid = [];

for (const item of items) {
  const row = item.json;

  // Skip completely empty rows
  const values = Object.values(row).filter(v => v !== null && v !== undefined && v !== '');
  if (values.length === 0) continue;

  // Normalize keys: lowercase, replace spaces with underscores
  const normalizedRow = {};
  for (const [key, value] of Object.entries(row)) {
    const normalizedKey = key.toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, '');
    normalizedRow[normalizedKey] = typeof value === 'string' ? value.trim() : value;
  }

  // Add metadata
  normalizedRow._imported_at = new Date().toISOString();
  normalizedRow._source_email = $('Extract Attachment').item.json.emailFrom;
  normalizedRow._source_file = $('Extract Attachment').item.json.filename;

  valid.push({ json: normalizedRow });
}

if (valid.length === 0) {
  throw new Error('File contained no valid rows after cleaning.');
}

return valid;

// Build summary after all rows are appended
const allItems = $input.all();
const rowCount = allItems.length;
const sourceFile = $('Extract Attachment').item.json.filename;
const sourceEmail = $('Extract Attachment').item.json.emailFrom;
const subject = $('Extract Attachment').item.json.emailSubject;

return [{
  json: {
    rowsImported: rowCount,
    sourceFile,
    sourceEmail,
    subject,
    completedAt: new Date().toISOString()
  }
}];

// Error handler: capture details for dead-letter queue
const error = $input.first().json;
return [{
  json: {
    failedAt: new Date().toISOString(),
    workflowName: 'Email Attachment → Google Sheets Parser',
    errorMessage: error.message || JSON.stringify(error),
    emailSubject: error.emailSubject || 'unknown'
  }
}];
